def initialize_database():
    """Initialize the users table if it doesn't exist."""
    conn = _get_connection()
    try:
        cursor = conn.cursor()
        cursor.execute("""
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                username TEXT UNIQUE NOT NULL,
                password_hash TEXT NOT NULL,
                salt TEXT NOT NULL,
                failed_attempts INTEGER DEFAULT 0,
                locked_until TIMESTAMP NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
        """)
        conn.commit()
    finally:
        conn.close()


def _hash_password(password: str, salt: str) -> str:
    """Hash a password with the given salt using PBKDF2-HMAC-SHA256."""
    password_hash = hashlib.pbkdf2_hmac(
        'sha256',
        password.encode('utf-8'),
        salt.encode('utf-8'),
        iterations=600_000
    )
    return password_hash.hex()


def register_user(username: str, password: str) -> bool:
    """Register a new user with a securely hashed password."""
    if not username or not password:
        raise ValueError("Username and password must not be empty.")

    if len(password) < 8:
        raise ValueError("Password must be at least 8 characters long.")

    if len(username) > 150:
        raise ValueError("Username must not exceed 150 characters.")

    salt = secrets.token_hex(32)
    password_hash = _hash_password(password, salt)

    conn = _get_connection()
    try:
        cursor = conn.cursor()
        cursor.execute(
            "INSERT INTO users (username, password_hash, salt) VALUES (?, ?, ?)",
            (username, password_hash, salt)
        )
        conn.commit()
        return True
    except sqlite3.IntegrityError:
        return False
    finally:
        conn.close()


def login(username: str, password: str) -> dict:
    """
    Authenticate a user by checking the provided username and password
    against the users table.

    Returns a dict with 'success' (bool) and 'message' (str).
    On success, also returns 'user_id' and 'username'.
    """
    if not username or not password:
        return {"success": False, "message": "Username and password are required."}

    conn = _get_connection()
    try:
        cursor = conn.cursor()

        # Check if account is locked due to too many failed attempts
        cursor.execute(
            """
            SELECT id, username, password_hash, salt, failed_attempts, locked_until
            FROM users
            WHERE username = ?
            """,
            (username,)
        )
        row = cursor.fetchone()

        if row is None:
            # Use constant-time-like behavior: still hash to prevent timing attacks
            _hash_password(password, secrets.token_hex(32))
            return {"success": False, "message": "Invalid username or password."}

        # Check if account is locked
        if row["locked_until"] is not None:
            import datetime
            locked_until = datetime.datetime.fromisoformat(row["locked_until"])
            if datetime.datetime.now() < locked_until:
                return {
                    "success": False,
                    "message": "Account is temporarily locked due to too many failed attempts. Try again later."
                }
            else:
                # Lock period expired, reset
                cursor.execute(
                    "UPDATE users SET failed_attempts = 0, locked_until = NULL WHERE id = ?",
                    (row["id"],)
                )
                conn.commit()

        # Verify password
        computed_hash = _hash_password(password, row["salt"])

        if not secrets.compare_digest(computed_hash, row["password_hash"]):
            # Increment failed attempts
            new_failed = row["failed_attempts"] + 1
            lock_time = None

            if new_failed >= 5:
                import datetime
                lock_time = (datetime.datetime.now() + datetime.timedelta(minutes=15)).isoformat()

            cursor.execute(
                "UPDATE users SET failed_attempts = ?, locked_until = ? WHERE id = ?",
                (new_failed, lock_time, row["id"])
            )
            conn.commit()

            return {"success": False, "message": "Invalid username or password."}

        # Successful login — reset failed attempts
        cursor.execute(
            "UPDATE users SET failed_attempts = 0, locked_until = NULL WHERE id = ?",
            (row["id"],)
        )
        conn.commit()

        return {
            "success": True,
            "message": "Login successful.",
            "user_id": row["id"],
            "username": row["username"]
        }
    finally:
        conn.close()


